namespace sv_43cf4b8c9d2843e2862371338bb69362.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// Interactive components subscribe to <see cref="OnChange"/> to re-render
/// when any component mutates the theme.
/// </summary>
public sealed class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#0d6efd"; // Bootstrap primary blue

    public event Action? OnChange;

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            OnChange?.Invoke();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            OnChange?.Invoke();
        }
    }

    public string CssClass => _theme switch
    {
        Theme.Dark => "theme-dark",
        Theme.System => "theme-system",
        _ => "theme-light"
    };
}

@* 
    Interactive island that lives in the static layout.
    Because it has its own @rendermode, it joins the circuit
    and can subscribe to the shared ThemeService.
*@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator badge rounded-pill @BadgeClass">
    @Icon @ThemeService.Theme
</span>

@code {
    private string BadgeClass => ThemeService.Theme switch
    {
        Theme.Dark => "text-bg-dark",
        Theme.System => "text-bg-secondary",
        _ => "text-bg-light border"
    };

    private string Icon => ThemeService.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm @ButtonClass" @onclick="CycleTheme" title="Toggle theme">
    @Icon
</button>

@code {
    private string ButtonClass => ThemeService.Theme switch
    {
        Theme.Dark => "btn-light",
        _ => "btn-dark"
    };

    private string Icon => ThemeService.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            Theme.System => Theme.Light,
            _ => Theme.Light
        };
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <button class="btn @(ThemeService.Theme == t ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = t">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color"
                   class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span class="badge rounded-pill" style="background-color: @ThemeService.AccentColor;">
                @ThemeService.AccentColor
            </span>
        </div>

        <h5 class="card-title">Preview</h5>
        <p>
            Current theme: <strong>@ThemeService.Theme</strong><br />
            Accent: <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </p>
    </div>
</div>

@code {
    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

