@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <button class="btn @(ThemeService.Theme == t ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = t">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color"
                   class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span class="badge rounded-pill" style="background-color: @ThemeService.AccentColor;">
                @ThemeService.AccentColor
            </span>
        </div>

        <h5 class="card-title">Preview</h5>
        <p>
            Current theme: <strong>@ThemeService.Theme</strong><br />
            Accent: <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </p>
    </div>
</div>

@code {
    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

